import React, { useState, useEffect } from 'react';
import './Results.css';

const LABELS = ['Before', 'After', 'Before', 'After', 'Before', 'After', 'Before', 'After'];
const DURATIONS = ['3 months', '6 months', '4 months', '5 months', '3 months', '8 months', '4 months', '6 months'];
const TYPES = ['Gaps', 'Crowding', 'Overbite', 'Gaps', 'Crooked', 'Crowding', 'Spacing', 'Overbite'];

export default function Results() {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const ctrl = new AbortController();
    fetch('https://dummyjson.com/products?limit=8&select=id,title,thumbnail,rating', { signal: ctrl.signal })
      .then(r => { if (!r.ok) throw new Error('Failed'); return r.json(); })
      .then(d => { setItems(d.products); setLoading(false); })
      .catch(e => { if (e.name !== 'AbortError') { setError('Could not load results.'); setLoading(false); } });
    return () => ctrl.abort();
  }, []);

  return (
    <section className="results-section">
      <div className="results-inner">
        <h2 className="results-title">Results You'll Love</h2>

        {loading && (
          <div className="results-grid">
            {[...Array(8)].map((_, i) => (
              <div key={i} className="skeleton-card">
                <div className="skel-img" />
                <div className="skel-line short" />
                <div className="skel-line long" />
              </div>
            ))}
          </div>
        )}

        {error && (
          <div className="results-error">
            <p>⚠️ {error}</p>
            <button onClick={() => window.location.reload()}>Retry</button>
          </div>
        )}

        {!loading && !error && (
          <div className="results-grid">
            {items.map((item, i) => (
              <div key={item.id} className="result-card">
                <div className="rc-img-wrap">
                  <img
                    src={`https://picsum.photos/seed/teeth${item.id}/260/220`}
                    alt={`Result ${i + 1}`}
                    className="rc-img"
                  />
                  <span className={`rc-badge ${LABELS[i] === 'After' ? 'rc-after' : 'rc-before'}`}>{LABELS[i]}</span>
                </div>
                <div className="rc-body">
                  <span className="rc-type">{TYPES[i]}</span>
                  <span className="rc-dur">{DURATIONS[i]}</span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}
